sql:
SELECT AVG(rating) AS average_rating
FROM restaurants
WHERE cuisine_type = 'American' AND neighborhood = 'Mission District';

SELECT AVG(rating) AS average_rating, COUNT(*) AS restaurant_count
FROM restaurants
WHERE cuisine_type = 'American';

SELECT MAX(total_reviews) AS highest_cumulative_review_count
FROM (
    SELECT neighborhood, SUM(review_count) AS total_reviews
    FROM restaurants
    GROUP BY neighborhood
) AS neighborhood_review_sums;

external_knowledge:
- "American cuisine" refers to dishes commonly found in the United States, such as burgers, steaks, and fried chicken;
- "Noe Valley" is a neighborhood in San Francisco, known for its vibrant dining scene;
- "Average rating" is calculated by averaging all the ratings given to restaurants in the database.

